{% extends '@PrestaShop/Admin/layout.html.twig' %}

{% set layoutHeaderToolbarBtn = {
  add: {
    href: path('admin_title_create'),
    desc: 'Add new title'|trans({}, 'Admin.Shopparameters.Feature'),
    icon: 'add_circle_outline',
  }
}
%}
{% set enableSidebar = true %}

{% block content %}
  {% block titles_list_panel %}
    {% include '@PrestaShop/Admin/Common/Grid/grid_panel.html.twig' with {'grid': titleGrid} %}
  {% endblock %}
{% endblock %}

{% block javascripts %}
  {{ parent() }}

  <script src=\"{{ asset('themes/new-theme/public/title.bundle.js') }}\"></script>
  <script src=\"{{ asset('themes/default/js/bundle/pagination.js') }}\"></script>
{% endblock %}
